// Script: generar_165_mejora2_obs_resuelta.js
// MEJORA 2: Marcar observación como Resuelta en Prevención.
//
// IMPORTANTE: Antes de correr este script, ejecutar en Supabase
// el archivo 17_observaciones_evoluciones.sql como "New snippet":
//   alter table observaciones
//     add column if not exists estado text not null default 'activa'...
//     add column if not exists fecha_resolucion date;
//
// Cambios en prevencion/page.tsx:
// - Observaciones ACTIVAS muestran botón "✓ Marcar como resuelta"
//   que abre un modal con FechaSelector (no input nativo)
// - Modal z-[60], body.overflow bloqueado, maxHeight calc(100vh-80px)
// - Observaciones RESUELTAS se colapsan bajo "✅ Resueltas (N)"
//   con badge verde, fecha resolución y botón "Reactivar"
// - Función reactivarObs() para volver una obs a estado activa
//
// Cambios en vet/page.tsx (solo lectura):
// - Observaciones muestran badge Activa/Resuelta
// - Si está resuelta, muestra la fecha de resolución
//
// FechaSelector: ya actualizado con días de la semana (generar_164)

const fs = require('fs'); const path = require('path');
function tsx(r, b64) {
  const f = path.join(...r.split('/'));
  const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8'));
  console.log('OK: ' + f);
}
tsx('app/prevencion/page.tsx', "");
tsx('app/vet/page.tsx', "");
tsx('components/FechaSelector.tsx', "");
